fun solve(s: String): Array<String> {
    val existingSegments = mutableSetOf<String>()
    val segments = mutableListOf<String>()
    var currentStart = 0
    while (currentStart < s.length) {
        var currentSegment = ""
        for (i in currentStart until s.length) {
            currentSegment += s[i]
            if (!existingSegments.contains(currentSegment)) {
                existingSegments.add(currentSegment)
                segments.add(currentSegment)
                currentStart = i + 1
                break
            }
        }
    }
    return segments.toTypedArray()
}
